    //图片转化成base64字符�? 
    public static String GetImageStr()  
    {//将图片文件转化为字节数组字符串，并对其进行Base64编码处理  
        String imgFile = "c:/imageCode.jpg";//待处理的图片  
        InputStream in = null;  
        byte[] data = null;  
        //读取图片字节数组  
        try   
        {  
            in = new FileInputStream(imgFile);          
            data = new byte[in.available()];  
            in.read(data);  
            in.close();  
        }   
        catch (IOException e)   
        {  
            e.printStackTrace();  
        }  
        //对字节数组Base64编码  
        BASE64Encoder encoder = new BASE64Encoder();  
        return encoder.encode(data);//返回Base64编码过的字节数组字符�? 
    }  
      
    //base64字符串转化成图片  
    public static boolean GenerateImage(String imgStr,String address)  
    {   //对字节数组字符串进行Base64解码并生成图�? 
        if (imgStr == null) //图像数据为空  
            return false;  
        BASE64Decoder decoder = new BASE64Decoder();  
        try   
        {  
            //Base64解码  
            byte[] b = decoder.decodeBuffer(imgStr);  
            for(int i=0;i<b.length;++i)  
            {  
                if(b[i]<0)  
                {//调整异常数据  
                    b[i]+=256;  
                }  
            }  
            //生成jpeg图片  
            OutputStream out = null ;
            String imgFilePath = null ;
            
            
        //    System.out.println("relativelyPath="+relativelyPath) ;
            
            if(address.contains("Mars")){ 
            	 
            
            	  imgFilePath = address+"imageCode.jpg";//新生成的图片  
            	  File f = new File(imgFilePath) ;
            	  
            	  if(f.exists()){
            		  f.deleteOnExit();
            	  }
            	  
            	  Thread.sleep(2000);
            	  
            	  out = new FileOutputStream(imgFilePath);  
            	 
            	
            }else{
                imgFilePath = "c:/imageCode.jpg";//新生成的图片  
                
                File f = new File(imgFilePath) ;
          	  
          	  if(f.exists()){
          		  f.deleteOnExit();
          	  }
                 out = new FileOutputStream(imgFilePath);  
            }
                
            out.write(b);  
            out.flush();  
            out.close();  
            return true; 
        }   
        catch (Exception e)   
        {  
            return false;  
        }  
    }  
    
    
